sql:
SELECT AVG(temperature_max_avg)
FROM monthly_data
WHERE station_id = 0 AND SUBSTR(date, 6, 2) = '01';

SELECT advisory_type, advisory_message, advisory_level
FROM advisories
WHERE station_id = 0;

external_knowledge:
- 'Frosty whispers' metaphorically refer to the average minimum temperature;
- 'Fiery breaths' metaphorically refer to the average maximum temperature;
- The 'standard they're measured by' refers to the unit of measurement (°C).

sql:
SELECT forecast_id, date, temperature_min, temperature_max
FROM forecasts
WHERE station_id = 1 AND strftime('%m', date) = '01';

external_knowledge:
- 'coldest month of last year' refers to January 2022;
- 'typical low and high temperature readings' refers to the average minimum and maximum temperatures;
- 'weather stations' are identified by their names and unique identifiers;
- 'coldest month' is inferred as January based on common understanding in many regions.

sql:
SELECT * 
FROM yearly_data 
WHERE year = 2022;

SELECT station_id, temperature_min, temperature_max, rainfall, rain_days, wind_speed, humidity, pressure
FROM weather_data
WHERE date = (SELECT MAX(date) FROM weather_data);

external_knowledge:
- 'ground-based sentinels of the climate' refers to weather stations that are of the 'surface' type;
- 'born after the millennium's dawn' means installed after the year 2000;
- 'cold whispers' metaphorically represents the average minimum temperature;
- 'wet embraces' symbolically represents the average rainfall.

- 'stood out as the wettest' implies having the highest rainfall; 
- 'each month' refers to the rainfall totals over different months; 
- 'amount of precipitation' is equivalent to the total rainfall in millimeters.

sql:
SELECT AVG((temperature_min_avg + temperature_max_avg) / 2) AS average_temperature
FROM yearly_data
WHERE station_id = 1 AND year = 2022;
